    parser = etree.XMLParser(
        dtd_validation=True,      # Enable DTD validation for backward compatibility
        no_network=True,          # Prevent network access for external entities
        resolve_entities=False,   # Disable entity resolution to prevent XXE
        load_dtd=True            # Load DTD but don't resolve external entities
    )
    
